import pandas as pd
import json

def generate_broadcast_report(raw_forecast, health_advisories):
    # 1. Aggregate raw data into a DataFrame (Daily Summary)
    df = pd.DataFrame(raw_forecast)
    df['date'] = pd.to_datetime(df['date'])

    # Ensure daily aggregation (in case of multiple entries per day, though sample is daily)
    daily_summary = df.groupby('date').agg({
        'temp_max_c': 'max',
        'precip_prob': 'max',
        'wind_speed_kmh': 'max'
    }).reset_index()

    # 2. Translate technical terms to layperson-friendly language
    def translate_precip(prob):
        if prob >= 0.8:
            return "Very likely to rain"
        elif prob >= 0.6:
            return "High chance of rain"
        elif prob >= 0.4:
            return "Possible rain"
        else:
            return "Little to no chance of rain"

    def translate_wind(speed):
        if speed >= 50:
            return "Strong winds expected"
        elif speed >= 30:
            return "Breezy conditions"
        else:
            return "Calm to light winds"

    daily_summary['precip_description'] = daily_summary['precip_prob'].apply(translate_precip)
    daily_summary['wind_description'] = daily_summary['wind_speed_kmh'].apply(translate_wind)

    # 3. Cross-reference with health advisories to generate warnings
    warnings = []
    for _, row in daily_summary.iterrows():
        date_str = row['date'].strftime('%Y-%m-%d')
        day_warnings = []

        for advisory in health_advisories:
            if advisory['condition'] == 'Heat' and row['temp_max_c'] > advisory['threshold_c']:
                day_warnings.append(f"HEAT ADVISORY: {advisory['message']} (Max Temp: {row['temp_max_c']}°C)")
            elif advisory['condition'] == 'Wind' and row['wind_speed_kmh'] > advisory['threshold_kmh']:
                day_warnings.append(f"WIND ADVISORY: {advisory['message']} (Wind Speed: {row['wind_speed_kmh']} km/h)")

        if day_warnings:
            warnings.append({"date": date_str, "alerts": day_warnings})

    # 4. Construct the structured JSON report
    # Summary for Public
    public_summary = []
    for _, row in daily_summary.iterrows():
        entry = {
            "date": row['date'].strftime('%A, %B %d, %Y'),
            "high": f"{row['temp_max_c']}°C",
            "precipitation": row['precip_description'],
            "wind": row['wind_description']
        }
        # Check if there are specific alerts for this date
        date_alerts = [w['alerts'] for w in warnings if w['date'] == row['date'].strftime('%Y-%m-%d')]
        if date_alerts:
            entry["public_alerts"] = date_alerts[0]
        public_summary.append(entry)

    # Technical Details
    technical_details = {
        "raw_data_points": len(raw_forecast),
        "forecast_period_days": len(daily_summary),
        "daily_metrics": daily_summary.to_dict(orient='records'),
        "active_advisories": warnings
    }

    report = {
        "broadcast_report": {
            "summary_for_public": public_summary,
            "technical_details": technical_details
        }
    }

    return report

# Example Usage with provided context data
if __name__ == "__main__":
    data_sample = {
        "raw_forecast": [
            {
                "date": "2023-10-05",
                "temp_max_c": 36.5,
                "precip_prob": 0.1,
                "wind_speed_kmh": 15.0
            },
            {
                "date": "2023-10-06",
                "temp_max_c": 22.0,
                "precip_prob": 0.8,
                "wind_speed_kmh": 45.0
            }
        ],
        "health_advisories": [
            {
                "condition": "Heat",
                "threshold_c": 35.0,
                "message": "Risk of heat exhaustion"
            },
            {
                "condition": "Wind",
                "threshold_kmh": 40.0,
                "message": "Risk of falling branches"
            }
        ]
    }

    result = generate_broadcast_report(data_sample['raw_forecast'], data_sample['health_advisories'])
    print(json.dumps(result, indent=2))
